// // This module calculates two addresses based on a current address and a displacement value. If the displacement is less than 128, it subtracts the displacement from the current address; otherwise, it adds the displacement to the current address.
module top_module(
cur_addr,
disp,
disp_addr,
one_addr
);input	  wire  [11:0]	cur_addr;
input	  wire  [7:0]	  disp;
output	wire  [11:0]	disp_addr;
output	wire  [11:0]	one_addr;

assign disp_addr = 
                   (disp>=8'b10000000) ? cur_addr+disp+12'b000000000001-12'b100000000:

                   cur_addr+disp+12'b1;

assign one_addr = cur_addr + 12'b000000000001;

endmodule
